namespace sv_7f09928bd97b485a8a442c92c9258405.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that tracks the currently selected warehouse for a single user circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "wh-a", Name = "Warehouse A" },
        new() { Id = "wh-b", Name = "Warehouse B" },
        new() { Id = "wh-c", Name = "Warehouse C" },
    ];

    public string CurrentWarehouseId { get; private set; } = AvailableWarehouses[0].Id;
    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == CurrentWarehouseId) return;
        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_7f09928bd97b485a8a442c92c9258405.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and notifies all subscribers
/// when new data arrives.  One instance per circuit keeps each user's state independent.
/// </summary>
public class InventoryAlertService
{
    private static readonly Random _rng = Random.Shared;

    public int LatestLowStockCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query that returns the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate varying results per warehouse
        int count = _rng.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches a fresh count for the given warehouse and notifies ALL subscribers.
    /// Called by the polling component so every badge/dashboard updates together.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

