@rendermode InteractiveServer

@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock items:
            <span class="badge bg-warning text-dark fs-5">@AlertService.LatestLowStockCount</span>
        </p>
        <p class="text-muted small mb-0">
            Auto-refreshes every 10 seconds. Last checked: @_lastChecked?.ToString("T")
        </p>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;
    private Action? _alertHandler;
    private Action? _warehouseHandler;

    protected override async Task OnInitializedAsync()
    {
        // Subscribe to alert changes so we update when new data arrives.
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;

        // Subscribe to warehouse changes so we immediately refresh on switch.
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        // Initial fetch + start polling.
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;

        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
                _lastChecked = DateTime.Now;
                // StateHasChanged is triggered via the OnAlertCountChanged subscription.
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task OnWarehouseChanged()
    {
        // Warehouse switched — immediately refresh instead of waiting for next tick.
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
    }

    public async ValueTask DisposeAsync()
    {
        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _timer?.Dispose();
    }
}

