        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
                _lastChecked = DateTime.Now;
                // StateHasChanged is triggered via the OnAlertCountChanged subscription.
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task OnWarehouseChanged()
    {
        // Warehouse switched — immediately refresh instead of waiting for next tick.
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
    }

    public async ValueTask DisposeAsync()
    {
        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _timer?.Dispose();
    }
}

